// ── Scoring Engine (inlined from scoring/scoring-engine.ts) ──────────────
// This is a direct copy of the pure function — no imports needed in n8n.

const CATEGORY_WEIGHTS = { market: 0.28, tech: 0.22, team: 0.15, future: 0.15, certs: 0.10, risk: 0.10 };

function round2(n) { return Math.round(n * 100) / 100; }
function clamp(n, min, max) { return Math.min(Math.max(n, min), max); }

function computeScores(metricValues, allMetrics) {
  const categories = Object.keys(CATEGORY_WEIGHTS);
  const totalPerCat = { tech: 0, certs: 0, market: 0, future: 0, team: 0, risk: 0 };
  for (const m of allMetrics) { if (m.category in totalPerCat) totalPerCat[m.category]++; }

  const byCat = { tech: [], certs: [], market: [], future: [], team: [], risk: [] };
  for (const mv of metricValues) { if (mv.category in byCat) byCat[mv.category].push(mv); }

  const catScores = {};

  for (const cat of categories) {
    const populated = byCat[cat];
    const total = totalPerCat[cat];
    if (populated.length === 0) {
      catScores[cat] = { category: cat, raw_score: 0, weighted_score: 0, populated_metrics: 0, total_metrics: total, confidence_breakdown: { verified_doc: 0, llm_inferred: 0, self_reported: 0 } };
      continue;
    }
    const totalW = populated.reduce((s, mv) => s + Number(mv.weight), 0);
    const wSum = populated.reduce((s, mv) => s + Number(mv.weight) * Number(mv.score), 0);
    const wScore = totalW > 0 ? wSum / totalW : 0;
    const rawScore = populated.reduce((s, mv) => s + Number(mv.score), 0) / populated.length;
    const confW = { verified_doc: 0, llm_inferred: 0, self_reported: 0 };
    for (const mv of populated) confW[mv.confidence_tag] = (confW[mv.confidence_tag] || 0) + Number(mv.weight);
    catScores[cat] = {
      category: cat,
      raw_score: round2(rawScore),
      weighted_score: round2(clamp(wScore, 0, 10)),
      populated_metrics: populated.length,
      total_metrics: total,
      confidence_breakdown: {
        verified_doc:  totalW > 0 ? round2(confW.verified_doc  / totalW) : 0,
        llm_inferred:  totalW > 0 ? round2(confW.llm_inferred  / totalW) : 0,
        self_reported: totalW > 0 ? round2(confW.self_reported / totalW) : 0,
      },
    };
  }

  let totalScore = 0;
  for (const cat of categories) totalScore += CATEGORY_WEIGHTS[cat] * catScores[cat].weighted_score;
  const profilePct = allMetrics.length > 0 ? round2((metricValues.length / allMetrics.length) * 100) : 0;

  return { categories: catScores, total_weighted_score: round2(clamp(totalScore, 0, 10)), profile_completeness_pct: clamp(profilePct, 0, 100) };
}

// ── Run it ────────────────────────────────────────────────────────────────
const data = $input.first().json;
const startup_id = $('Execute Workflow Trigger').first().json.startup_id;
const triggered_by = $('Execute Workflow Trigger').first().json.triggered_by || 'manual';

const result = computeScores(data.metric_values || [], data.all_metrics || []);

// Build the payload for POST /api/scores
const scoresPayload = Object.values(result.categories).map(c => ({
  startup_id,
  category:              c.category,
  raw_score:             c.raw_score,
  weighted_score:        c.weighted_score,
  populated_metrics:     c.populated_metrics,
  total_metrics:         c.total_metrics,
  confidence_breakdown:  c.confidence_breakdown,
  triggered_by,
}));

return [{ json: {
  startup_id,
  scores:                    scoresPayload,
  total_weighted_score:      result.total_weighted_score,
  profile_completeness_pct:  result.profile_completeness_pct,
} }];
